INSERT INTO questions (topic_id, enunciado, alt_a, alt_b, alt_c, alt_d, alt_e, gabarito, tipo, estilo_idecan, dificuldade, comentario_json, tags) VALUES ((SELECT id FROM topics WHERE nome = 'CTB_engenharia_fiscalizacao' LIMIT 1), 'Prefeitura de Campina Grande analisa projeto de shopping center em área que, segundo estudo de impacto, concentrará intenso fluxo de veículos. O secretário de planejamento questiona quais requisitos o CTB impõe antes da aprovação do empreendimento. Assinale a alternativa CORRETA:', 'Basta aprovação do projeto pelo município, pois estacionamento é faculdade do empreendedor.', 'Exige-se apenas licença ambiental, sendo dispensável anuência do órgão de trânsito.', 'O projeto deve contar com anuência prévia do órgão de trânsito com circunscrição sobre a via e previsão de área de estacionamento e vias de acesso.', 'A anuência do CONTRAN é obrigatória para qualquer edificação comercial em vias municipais.', NULL, 'C', 'lei_seca', 'lei_seca', 2, '{"o_que_testa":"Requisitos para aprovação de empreendimento que constitua pólo atrativo de trânsito (art. 93).","fundamento_legal":"CTB, art. 93: nenhum projeto de edificação que possa transformar-se em pólo atrativo de trânsito poderá ser aprovado sem prévia anuência do órgão ou entidade com circunscrição sobre a via e sem que do projeto conste área para estacionamento e indicação das vias de acesso adequadas.","passo_a_passo":["Shopping com alto fluxo = potencial pólo atrativo de trânsito.","A) Erra: estacionamento e anuência de trânsito são exigidos pelo art. 93.","B) Erra: licença ambiental não substitui anuência do órgão de trânsito.","C) Correta: reproduz o art. 93.","D) Erra: a anuência é do órgão com circunscrição sobre a via, não do CONTRAN diretamente."],"pegadinha":"Trocar anuência do órgão local de trânsito por anuência do CONTRAN ou dispensar estacionamento no projeto.","macete":"Pólo atrativo = anuência do órgão da via + estacionamento + acessos (art. 93).","estudo_reverso":["CTB art. 91","CTB art. 93","CTB art. 94"]}'::jsonb, '{"engenharia","art_93","empreendimento"}'::text[]);